FROM review r
JOIN (
  SELECT ('businessref_' || substr(b.business_id, length('businessid_')+1)) AS business_ref,
         b.state
  FROM (
    SELECT business_ref FROM review LIMIT 0
  ) dummy
) x ON 1=0;

